package com.google.gson.internal.bind;
import com.google.gson.JsonElement;
import com.google.gson.JsonPrimitive;
import com.google.gson.JsonSyntaxException;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.internal.$Gson$Types;
import com.google.gson.internal.JsonReaderInternalAccess;
import com.google.gson.internal.Streams;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.internal.ObjectConstructor;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentMatchers;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

import java.lang.reflect.Method;
import java.lang.reflect.Type;
import java.util.HashMap;
import java.util.Map;

public class MapTypeAdapterFactoryTest {

  @Mock
  private ConstructorConstructor constructorConstructor;

  @Mock
  private Gson gson;

  @Mock
  private ObjectConstructor<HashMap<?, ?>> objectConstructor;

  @BeforeEach
  public void setUp() {
    MockitoAnnotations.openMocks(this);
  }

  @Test
  public void create_shouldReturnNullIfNotMap() {
    MapTypeAdapterFactory factory = new MapTypeAdapterFactory(constructorConstructor, false);
    TypeToken<String> stringTypeToken = TypeToken.get(String.class);

    TypeAdapter<String> adapter = factory.create(gson, stringTypeToken);

    assertNull(adapter);
  }

  @Test
  public void create_shouldReturnAdapterForMap() throws Exception {
    MapTypeAdapterFactory factory = new MapTypeAdapterFactory(constructorConstructor, false);
    TypeToken<HashMap<String, Integer>> mapTypeToken = new TypeToken<HashMap<String, Integer>>() {};

    // Spy on factory to allow partial mocking
    MapTypeAdapterFactory spyFactory = spy(factory);

    Type keyType = String.class;
    TypeAdapter<String> keyAdapter = mock(TypeAdapter.class);

    // Use reflection to access private getKeyAdapter method and mock its call
    Method getKeyAdapterMethod = MapTypeAdapterFactory.class.getDeclaredMethod("getKeyAdapter", Gson.class, Type.class);
    getKeyAdapterMethod.setAccessible(true);
    doReturn(keyAdapter).when(spyFactory).createKeyAdapterMock(gson, keyType);

    // Instead of spying getKeyAdapter directly (private), override create() to call our mock
    // We'll create a subclass for this purpose:
    MapTypeAdapterFactory factoryWithMockedKeyAdapter = new MapTypeAdapterFactory(constructorConstructor, false) {
      @Override
      @SuppressWarnings("unchecked")
      protected TypeAdapter<?> getKeyAdapter(Gson context, Type keyTypeParam) {
        if (keyTypeParam.equals(keyType)) {
          return keyAdapter;
        }
        return super.getKeyAdapter(context, keyTypeParam);
      }
    };

    MapTypeAdapterFactory spyFactory2 = spy(factoryWithMockedKeyAdapter);

    TypeAdapter<Integer> valueAdapter = mock(TypeAdapter.class);
    when(gson.getAdapter(ArgumentMatchers.<TypeToken<Integer>>any())).thenReturn(valueAdapter);

    // Fix constructorConstructor.get() type mismatch by using raw TypeToken and raw ObjectConstructor
    @SuppressWarnings({"unchecked", "rawtypes"})
    TypeToken rawMapTypeToken = mapTypeToken;
    @SuppressWarnings({"unchecked", "rawtypes"})
    ObjectConstructor rawObjectConstructor = objectConstructor;

    when(constructorConstructor.get(rawMapTypeToken)).thenReturn(rawObjectConstructor);

    TypeAdapter<HashMap<String, Integer>> adapter = spyFactory2.create(gson, mapTypeToken);

    assertNotNull(adapter);
    assertEquals("com.google.gson.internal.bind.MapTypeAdapterFactory$Adapter", adapter.getClass().getName());
  }
}
